namespace sv_48d1f0ffc61c4d5e90b94a219311ce7e.Services;

public record Channel(int Id, string Name, string Description, int UnreadCount);
public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);
public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

@using sv_48d1f0ffc61c4d5e90b94a219311ce7e.Services

<div class="channel-sidebar">
    <h3 class="sidebar-title">Channels</h3>
    <ul class="channel-list">
        @foreach (var channel in Channels)
        {
            <li class="channel-item @(channel.Id == ActiveChannelId ? "active" : "")"
                @onclick="() => OnChannelSelected.InvokeAsync(channel.Id)">
                <div class="channel-name"># @channel.Name</div>
                <div class="channel-description">@Truncate(channel.Description, 40)</div>
                @if (channel.UnreadCount > 0)
                {
                    <span class="unread-badge">@channel.UnreadCount</span>
                }
            </li>
        }
    </ul>
</div>

@code {
    [Parameter, EditorRequired]
    public List<Channel> Channels { get; set; } = [];

    [Parameter]
    public int ActiveChannelId { get; set; }

    [Parameter]
    public EventCallback<int> OnChannelSelected { get; set; }

    private static string Truncate(string text, int maxLength) =>
        text.Length <= maxLength ? text : text[..maxLength] + "…";
}

.channel-sidebar {
    width: 100%;
    height: 100%;
    background-color: #2b2d42;
    color: #edf2f4;
    display: flex;
    flex-direction: column;
    overflow: hidden;
}

.sidebar-title {
    padding: 16px;
    margin: 0;
    font-size: 1.1rem;
    font-weight: 700;
    border-bottom: 1px solid #3a3d56;
}

.channel-list {
    list-style: none;
    margin: 0;
    padding: 8px 0;
    overflow-y: auto;
    flex: 1;
}

.channel-item {
    padding: 10px 16px;
    cursor: pointer;
    position: relative;
    transition: background-color 0.15s;
}

.channel-item:hover {
    background-color: #3a3d56;
}

.channel-item.active {
    background-color: #4a4e6a;
}

.channel-name {
    font-weight: 600;
    font-size: 0.95rem;
}

.channel-description {
    font-size: 0.75rem;
    color: #8d99ae;
    margin-top: 2px;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.unread-badge {
    position: absolute;
    right: 12px;
    top: 50%;
    transform: translateY(-50%);
    background-color: #ef233c;
    color: white;
    border-radius: 10px;
    padding: 1px 7px;
    font-size: 0.75rem;
    font-weight: 700;
    min-width: 18px;
    text-align: center;
}

@using sv_48d1f0ffc61c4d5e90b94a219311ce7e.Services

<div class="message-bubble" @onmouseenter="() => showActions = true" @onmouseleave="() => showActions = false">
    <div class="message-header">
        <span class="message-author">@Message.Author</span>
        <span class="message-time">@FormatRelativeTime(Message.SentAt)</span>
    </div>
    <div class="message-content">@Message.Content</div>

    @if (Message.Reactions.Count > 0)
    {
        <div class="reaction-bar">
            @foreach (var reaction in Message.Reactions)
            {
                <button class="reaction-badge" @onclick="() => OnReact.InvokeAsync(reaction.Emoji)">
                    @reaction.Emoji @reaction.Users.Count
                </button>
            }
        </div>
    }

    @if (ReplyCount > 0)
    {
        <button class="thread-link" @onclick="() => OnOpenThread.InvokeAsync()">
            @ReplyCount @(ReplyCount == 1 ? "reply" : "replies")
        </button>
    }

    @if (showActions)
    {
        <div class="message-actions">
            <button class="action-btn" @onclick="() => OnOpenThread.InvokeAsync()" title="Reply in thread">💬</button>
            <button class="action-btn" @onclick="ToggleEmojiPicker" title="Add reaction">😊</button>
        </div>
    }

    @if (showEmojiPicker)
    {
        <div class="emoji-picker">
            @foreach (var emoji in commonEmojis)
            {
                <button class="emoji-btn" @onclick="() => SelectEmoji(emoji)">@emoji</button>
            }
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public Message Message { get; set; } = default!;

    [Parameter]
    public int ReplyCount { get; set; }

    [Parameter]
    public EventCallback OnOpenThread { get; set; }

    [Parameter]
    public EventCallback<string> OnReact { get; set; }

    private bool showActions;
    private bool showEmojiPicker;

    private static readonly string[] commonEmojis = ["👍", "❤️", "😂", "🎉", "🤔", "👀"];

    private void ToggleEmojiPicker() => showEmojiPicker = !showEmojiPicker;

    private async Task SelectEmoji(string emoji)
    {
        showEmojiPicker = false;
        await OnReact.InvokeAsync(emoji);
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        if (diff.TotalMinutes < 1) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }
}

.message-bubble {
    padding: 8px 16px;
    position: relative;
    transition: background-color 0.1s;
}

.message-bubble:hover {
    background-color: #f0f0f3;
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.message-author {
    font-weight: 700;
    font-size: 0.95rem;
}

.message-time {
    font-size: 0.75rem;
    color: #8d99ae;
}

.message-content {
    font-size: 0.9rem;
    line-height: 1.45;
    white-space: pre-wrap;
    word-break: break-word;
}

.reaction-bar {
    display: flex;
    gap: 4px;
    margin-top: 4px;
    flex-wrap: wrap;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 3px;
    background-color: #e8eaf0;
    border: 1px solid #d0d3dc;
    border-radius: 12px;
    padding: 2px 8px;
    font-size: 0.8rem;
    cursor: pointer;
    transition: background-color 0.15s;
}

.reaction-badge:hover {
    background-color: #d0d5e0;
}

.thread-link {
    background: none;
    border: none;
    color: #2b6cb0;
    font-size: 0.8rem;
    font-weight: 600;
    cursor: pointer;
    padding: 4px 0 0;
    display: block;
}

.thread-link:hover {
    text-decoration: underline;
}

.message-actions {
    position: absolute;
    top: 4px;
    right: 12px;
    display: flex;
    gap: 2px;
    background: white;
    border: 1px solid #d0d3dc;
    border-radius: 6px;
    padding: 2px;
    box-shadow: 0 2px 6px rgba(0, 0, 0, 0.1);
}

.action-btn {
    background: none;
    border: none;
    cursor: pointer;
    padding: 4px 6px;
    border-radius: 4px;
    font-size: 1rem;
    line-height: 1;
}

.action-btn:hover {
    background-color: #f0f0f3;
}

.emoji-picker {
    display: flex;
    gap: 2px;
    background: white;
    border: 1px solid #d0d3dc;
    border-radius: 8px;
    padding: 4px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.12);
    position: absolute;
    right: 12px;
    top: 36px;
    z-index: 10;
}

.emoji-btn {
    background: none;
    border: none;
    cursor: pointer;
    padding: 4px 6px;
    font-size: 1.2rem;
    border-radius: 4px;
    line-height: 1;
}

.emoji-btn:hover {
    background-color: #f0f0f3;
}

@using sv_48d1f0ffc61c4d5e90b94a219311ce7e.Services
@inject IJSRuntime JS

<div class="message-area">
    <div class="area-header">
        <h2 class="area-channel-name"># @ChannelName</h2>
        <p class="area-channel-desc">@ChannelDescription</p>
    </div>

    <div class="message-list" @ref="messageListRef" @onscroll="HandleScroll">
        @if (IsLoadingMore)
        {
            <div class="loading-indicator">Loading older messages…</div>
        }
        @foreach (var msg in Messages)
        {
            <MessageBubble Message="msg"
                           ReplyCount="GetReplyCount(msg.Id)"
                           OnOpenThread="() => OnOpenThread.InvokeAsync(msg.Id)"
                           OnReact="(emoji) => OnReact.InvokeAsync((msg.Id, emoji))" />
        }
    </div>

    <div class="message-input-area">
        <textarea class="message-textarea"
                  @bind="newMessage"
                  @bind:event="oninput"
                  @onkeydown="HandleKeyDown"
                  placeholder="Type a message…"
                  rows="1"></textarea>
        <button class="send-btn" @onclick="SendMessage" disabled="@string.IsNullOrWhiteSpace(newMessage)">Send</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public string ChannelName { get; set; } = "";

    [Parameter]
    public string ChannelDescription { get; set; } = "";

    [Parameter, EditorRequired]
    public List<Message> Messages { get; set; } = [];

    [Parameter]
    public Dictionary<int, int> ThreadReplyCounts { get; set; } = new();

    [Parameter]
    public bool IsLoadingMore { get; set; }

    [Parameter]
    public EventCallback<int> OnOpenThread { get; set; }

    [Parameter]
    public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    [Parameter]
    public EventCallback<string> OnSendMessage { get; set; }

    [Parameter]
    public EventCallback OnLoadOlderMessages { get; set; }

    private string newMessage = "";
    private ElementReference messageListRef;

    private int GetReplyCount(int messageId) =>
        ThreadReplyCounts.TryGetValue(messageId, out var count) ? count : 0;

    private async Task SendMessage()
    {
        if (string.IsNullOrWhiteSpace(newMessage)) return;
        var content = newMessage;
        newMessage = "";
        await OnSendMessage.InvokeAsync(content);
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendMessage();
        }
    }

    private async Task HandleScroll()
    {
        var scrollTop = await JS.InvokeAsync<double>("eval", "document.querySelector('[b-message-list]')?.scrollTop ?? -1");
        if (scrollTop <= 0)
        {
            await OnLoadOlderMessages.InvokeAsync();
        }
    }

    public async Task ScrollToBottom()
    {
        await JS.InvokeVoidAsync("eval",
            "setTimeout(() => { const el = document.querySelector('.message-list'); if(el) el.scrollTop = el.scrollHeight; }, 50)");
    }
}

.message-area {
    display: flex;
    flex-direction: column;
    height: 100%;
    background-color: #ffffff;
}

.area-header {
    padding: 12px 16px;
    border-bottom: 1px solid #e2e4ea;
    flex-shrink: 0;
}

.area-channel-name {
    margin: 0;
    font-size: 1.1rem;
    font-weight: 700;
}

.area-channel-desc {
    margin: 2px 0 0;
    font-size: 0.8rem;
    color: #8d99ae;
}

.message-list {
