toolArgs.file_text:
.message-bubble {
    padding: 8px 16px;
    position: relative;
    transition: background-color 0.1s;
}

.message-bubble:hover {
    background-color: #f0f0f3;
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.message-author {
    font-weight: 700;
    font-size: 0.95rem;
}

.message-time {
    font-size: 0.75rem;
    color: #8d99ae;
}

.message-content {
    font-size: 0.9rem;
    line-height: 1.45;
    white-space: pre-wrap;
    word-break: break-word;
}

.reaction-bar {
    display: flex;
    gap: 4px;
    margin-top: 4px;
    flex-wrap: wrap;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 3px;
    background-color: #e8eaf0;
    border: 1px solid #d0d3dc;
    border-radius: 12px;
    padding: 2px 8px;
    font-size: 0.8rem;
    cursor: pointer;
    transition: background-color 0.15s;
}

.reaction-badge:hover {
    background-color: #d0d5e0;
}

.thread-link {
    background: none;
    border: none;
    color: #2b6cb0;
    font-size: 0.8rem;
    font-weight: 600;
    cursor: pointer;
    padding: 4px 0 0;
    display: block;
}

.thread-link:hover {
    text-decoration: underline;
}

.message-actions {
    position: absolute;
    top: 4px;
    right: 12px;
    display: flex;
    gap: 2px;
    background: white;
    border: 1px solid #d0d3dc;
    border-radius: 6px;
    padding: 2px;
    box-shadow: 0 2px 6px rgba(0, 0, 0, 0.1);
}

.action-btn {
    background: none;
    border: none;
    cursor: pointer;
    padding: 4px 6px;
    border-radius: 4px;
    font-size: 1rem;
    line-height: 1;
}

.action-btn:hover {
    background-color: #f0f0f3;
}

.emoji-picker {
    display: flex;
    gap: 2px;
    background: white;
    border: 1px solid #d0d3dc;
    border-radius: 8px;
    padding: 4px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.12);
    position: absolute;
    right: 12px;
    top: 36px;
    z-index: 10;
}

.emoji-btn {
    background: none;
    border: none;
    cursor: pointer;
    padding: 4px 6px;
    font-size: 1.2rem;
    border-radius: 4px;
    line-height: 1;
}

.emoji-btn:hover {
    background-color: #f0f0f3;
}

