@using sv_48d1f0ffc61c4d5e90b94a219311ce7e.Services
@inject IJSRuntime JS

<div class="message-area">
    <div class="area-header">
        <h2 class="area-channel-name"># @ChannelName</h2>
        <p class="area-channel-desc">@ChannelDescription</p>
    </div>

    <div class="message-list" @ref="messageListRef" @onscroll="HandleScroll">
        @if (IsLoadingMore)
        {
            <div class="loading-indicator">Loading older messages…</div>
        }
        @foreach (var msg in Messages)
        {
            <MessageBubble Message="msg"
                           ReplyCount="GetReplyCount(msg.Id)"
                           OnOpenThread="() => OnOpenThread.InvokeAsync(msg.Id)"
                           OnReact="(emoji) => OnReact.InvokeAsync((msg.Id, emoji))" />
        }
    </div>

    <div class="message-input-area">
        <textarea class="message-textarea"
                  @bind="newMessage"
                  @bind:event="oninput"
                  @onkeydown="HandleKeyDown"
                  placeholder="Type a message…"
                  rows="1"></textarea>
        <button class="send-btn" @onclick="SendMessage" disabled="@string.IsNullOrWhiteSpace(newMessage)">Send</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public string ChannelName { get; set; } = "";

    [Parameter]
    public string ChannelDescription { get; set; } = "";

    [Parameter, EditorRequired]
    public List<Message> Messages { get; set; } = [];

    [Parameter]
    public Dictionary<int, int> ThreadReplyCounts { get; set; } = new();

    [Parameter]
    public bool IsLoadingMore { get; set; }

    [Parameter]
    public EventCallback<int> OnOpenThread { get; set; }

    [Parameter]
    public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    [Parameter]
    public EventCallback<string> OnSendMessage { get; set; }

    [Parameter]
    public EventCallback OnLoadOlderMessages { get; set; }

    private string newMessage = "";
    private ElementReference messageListRef;

    private int GetReplyCount(int messageId) =>
        ThreadReplyCounts.TryGetValue(messageId, out var count) ? count : 0;

    private async Task SendMessage()
    {
        if (string.IsNullOrWhiteSpace(newMessage)) return;
        var content = newMessage;
        newMessage = "";
        await OnSendMessage.InvokeAsync(content);
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendMessage();
        }
    }

    private async Task HandleScroll()
    {
        var scrollTop = await JS.InvokeAsync<double>("eval", "document.querySelector('[b-message-list]')?.scrollTop ?? -1");
        if (scrollTop <= 0)
        {
            await OnLoadOlderMessages.InvokeAsync();
        }
    }

    public async Task ScrollToBottom()
    {
        await JS.InvokeVoidAsync("eval",
            "setTimeout(() => { const el = document.querySelector('.message-list'); if(el) el.scrollTop = el.scrollHeight; }, 50)");
    }
}

