toolArgs.file_text:
.message-area {
    display: flex;
    flex-direction: column;
    height: 100%;
    background-color: #ffffff;
}

.area-header {
    padding: 12px 16px;
    border-bottom: 1px solid #e2e4ea;
    flex-shrink: 0;
}

.area-channel-name {
    margin: 0;
    font-size: 1.1rem;
    font-weight: 700;
}

.area-channel-desc {
    margin: 2px 0 0;
    font-size: 0.8rem;
    color: #8d99ae;
}

.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
}

.loading-indicator {
    text-align: center;
    padding: 8px;
    font-size: 0.8rem;
    color: #8d99ae;
}

.message-input-area {
    display: flex;
    align-items: flex-end;
    gap: 8px;
    padding: 12px 16px;
    border-top: 1px solid #e2e4ea;
    flex-shrink: 0;
}

.message-textarea {
    flex: 1;
    resize: none;
    border: 1px solid #d0d3dc;
    border-radius: 8px;
    padding: 10px 12px;
    font-size: 0.9rem;
    font-family: inherit;
    line-height: 1.4;
    outline: none;
    transition: border-color 0.15s;
}

.message-textarea:focus {
    border-color: #2b6cb0;
}

.send-btn {
    background-color: #2b6cb0;
    color: white;
    border: none;
    border-radius: 8px;
    padding: 10px 20px;
    font-size: 0.9rem;
    font-weight: 600;
    cursor: pointer;
    transition: background-color 0.15s;
    flex-shrink: 0;
}

.send-btn:hover:not(:disabled) {
    background-color: #1e5191;
}

.send-btn:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

