toolArgs.file_text:
.thread-panel {
    display: flex;
    flex-direction: column;
    height: 100%;
    background-color: #fafbfc;
    border-left: 1px solid #e2e4ea;
}

.thread-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 12px 16px;
    border-bottom: 1px solid #e2e4ea;
    flex-shrink: 0;
}

.thread-title {
    margin: 0;
    font-size: 1rem;
    font-weight: 700;
}

.close-btn {
    background: none;
    border: none;
    font-size: 1.1rem;
    cursor: pointer;
    color: #8d99ae;
    padding: 4px 8px;
    border-radius: 4px;
    line-height: 1;
}

.close-btn:hover {
    background-color: #e2e4ea;
    color: #2b2d42;
}

.thread-root-message {
    padding: 12px 16px;
    background-color: #eef1f6;
    border-bottom: 1px solid #e2e4ea;
    flex-shrink: 0;
}

.root-author {
    font-weight: 700;
    font-size: 0.9rem;
    margin-bottom: 4px;
}

.root-content {
    font-size: 0.85rem;
    line-height: 1.4;
    color: #3a3d56;
    white-space: pre-wrap;
    word-break: break-word;
}

.thread-divider {
    padding: 8px 16px;
    font-size: 0.75rem;
    color: #8d99ae;
    border-bottom: 1px solid #e2e4ea;
    flex-shrink: 0;
}

.thread-replies {
    flex: 1;
    overflow-y: auto;
    padding: 4px 0;
}

.thread-reply {
    padding: 8px 16px;
}

.reply-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.reply-author {
    font-weight: 700;
    font-size: 0.85rem;
}

.reply-time {
    font-size: 0.7rem;
    color: #8d99ae;
}

.reply-content {
    font-size: 0.85rem;
    line-height: 1.4;
    white-space: pre-wrap;
    word-break: break-word;
}

.thread-input-area {
    display: flex;
    align-items: flex-end;
    gap: 8px;
    padding: 12px 16px;
    border-top: 1px solid #e2e4ea;
    flex-shrink: 0;
}

.thread-textarea {
    flex: 1;
    resize: none;
    border: 1px solid #d0d3dc;
    border-radius: 8px;
    padding: 8px 10px;
    font-size: 0.85rem;
    font-family: inherit;
    line-height: 1.4;
    outline: none;
    transition: border-color 0.15s;
}

.thread-textarea:focus {
    border-color: #2b6cb0;
}

.reply-btn {
    background-color: #2b6cb0;
    color: white;
    border: none;
    border-radius: 8px;
    padding: 8px 16px;
    font-size: 0.85rem;
    font-weight: 600;
    cursor: pointer;
    transition: background-color 0.15s;
    flex-shrink: 0;
}

.reply-btn:hover:not(:disabled) {
    background-color: #1e5191;
}

.reply-btn:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

