    <div class="chat-main @(isThreadOpen ? "" : "chat-main-full")">
        @if (activeChannel is not null)
        {
            <MessageArea @ref="messageAreaRef"
                         ChannelName="@activeChannel.Name"
                         ChannelDescription="@activeChannel.Description"
                         Messages="messages"
                         ThreadReplyCounts="threadReplyCounts"
                         IsLoadingMore="isLoadingMore"
                         OnOpenThread="OpenThread"
                         OnReact="HandleReaction"
                         OnSendMessage="SendMessage"
                         OnLoadOlderMessages="LoadOlderMessages" />
        }
        else
        {
            <div class="no-channel-selected">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </div>

    @if (isThreadOpen && threadRootMessage is not null)
    {
        <div class="chat-thread">
            <ThreadPanel RootMessage="threadRootMessage"
                         Replies="threadReplies"
                         OnClose="CloseThread"
                         OnSendReply="SendThreadReply" />
        </div>
    }
</div>

@code {
    private List<Channel> channels = [];
    private List<Message> messages = [];
    private Channel? activeChannel;
    private int activeChannelId;
    private Dictionary<int, int> threadReplyCounts = new();

    private bool isThreadOpen;
    private Message? threadRootMessage;
    private List<Message> threadReplies = [];

    private bool isLoadingMore;
    private const int PageSize = 30;

    private MessageArea? messageAreaRef;

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();

        if (channels.Count > 0)
        {
            await SelectChannel(channels[0].Id);
        }
    }

    private async Task SelectChannel(int channelId)
    {
        activeChannelId = channelId;
        activeChannel = channels.Find(c => c.Id == channelId);
        messages = [];
        threadReplyCounts = new();

        CloseThread();

        messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        await BuildThreadReplyCounts();
        await ChatService.MarkChannelReadAsync(channelId);

        // Update unread count locally
        var idx = channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
        {
            channels[idx] = channels[idx] with { UnreadCount = 0 };
        }

        StateHasChanged();

        if (messageAreaRef is not null)
        {
            await messageAreaRef.ScrollToBottom();
        }
    }

    private async Task BuildThreadReplyCounts()
    {
        threadReplyCounts = new();
        // Messages with ReplyToId are replies; count them per root
        foreach (var msg in messages.Where(m => m.ReplyToId is not null))
        {
            threadReplyCounts.TryGetValue(msg.ReplyToId!.Value, out var count);
            threadReplyCounts[msg.ReplyToId!.Value] = count + 1;
        }

        // Also check for threads on messages that don't have inline replies
        foreach (var msg in messages.Where(m => m.ReplyToId is null && !threadReplyCounts.ContainsKey(m.Id)))
        {
            // Will be populated when thread is opened
        }

        await Task.CompletedTask;
    }

    private async Task SendMessage(string content)
    {
        if (activeChannel is null) return;

        var newMsg = await ChatService.SendMessageAsync(activeChannel.Id, content, null);
        messages.Add(newMsg);
        StateHasChanged();

        if (messageAreaRef is not null)
        {
            await messageAreaRef.ScrollToBottom();
        }
    }

    private async Task HandleReaction((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        // Optimistic local update
        var msg = messages.Find(m => m.Id == args.MessageId);
        if (msg is not null)
        {
            var reaction = msg.Reactions.Find(r => r.Emoji == args.Emoji);
            if (reaction is not null)
            {
                reaction.Users.Add("You");
            }
            else
            {
                msg.Reactions.Add(new Reaction(args.Emoji, ["You"]));
            }
            StateHasChanged();
        }
    }

    private async Task OpenThread(int rootMessageId)
    {
        threadRootMessage = messages.Find(m => m.Id == rootMessageId);
        if (threadRootMessage is null) return;

        threadReplies = await ChatService.GetThreadAsync(rootMessageId);
        isThreadOpen = true;

        // Update reply count
        threadReplyCounts[rootMessageId] = threadReplies.Count;
        StateHasChanged();
    }

    private void CloseThread()
    {
        isThreadOpen = false;
        threadRootMessage = null;
        threadReplies = [];
    }

    private async Task SendThreadReply(string content)
    {
        if (threadRootMessage is null || activeChannel is null) return;

        var reply = await ChatService.SendMessageAsync(activeChannel.Id, content, threadRootMessage.Id);
        threadReplies.Add(reply);

        // Update reply count
        threadReplyCounts[threadRootMessage.Id] = threadReplies.Count;
        StateHasChanged();
    }

    private async Task LoadOlderMessages()
    {
        if (isLoadingMore || activeChannel is null) return;

        isLoadingMore = true;
        StateHasChanged();

        var olderMessages = await ChatService.GetMessagesAsync(activeChannel.Id, messages.Count, PageSize);
        if (olderMessages.Count > 0)
        {
            messages.InsertRange(0, olderMessages);
            await BuildThreadReplyCounts();
        }

        isLoadingMore = false;
        StateHasChanged();
    }
}

