.chat-layout {
    display: flex;
    height: 100vh;
    overflow: hidden;
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
}

.chat-sidebar {
    width: 20%;
    min-width: 200px;
    flex-shrink: 0;
}

.chat-main {
    width: 55%;
    flex-shrink: 0;
    transition: width 0.2s ease;
}

.chat-main-full {
    width: 80%;
}

.chat-thread {
    width: 25%;
    min-width: 260px;
    flex-shrink: 0;
}

.no-channel-selected {
    display: flex;
    align-items: center;
    justify-content: center;
    height: 100%;
    color: #8d99ae;
    font-size: 1.1rem;
}

